SELECT t0.* FROM activity_sign t0
LEFT JOIN user t1 ON t1.user_id = t0.user_id AND t1.deleted = 0
WHERE t0.deleted = 0
 AND t0.show_name LIKE CONCAT('%', #{showName}, '%') 
 AND t0.user_name = #{userName} 
 AND t0.activity_id = #{activityId} 
ORDER BY t0.sign_id DESC
LIMIT #{page}, #{limit}

SELECT COUNT(1) FROM activity_sign t0
LEFT JOIN user t1 ON t1.user_id = t0.user_id AND t1.deleted = 0
WHERE t0.deleted = 0
 AND t0.show_name LIKE CONCAT('%', #{showName}, '%') 
 AND t0.user_name = #{userName} 
 AND t0.activity_id = #{activityId}
